// log.error("  owner........"+owner.toXml());
// log.error("  newOwner........"+newOwner);


if(owner!=null){
  Iterator it=ObjectUtil.getWorkgroupMembers(context,owner,properties);

  if(it!=null @and !it.hasNext()){

    log.error(" if it is empty the  item is before nullifying item........"+item.toXml());
    item.setState(WorkItem.State.Canceled);
    item.setExpiration(new Date());
    log.error(" item expiry checking........"+item.isExpired());
    log.error(" if it is empty the  item is after nullifying item........"+item.toXml());

  }else{

    log.error(" if it is not empty the  item is not nullifying item........"+item.toXml());
    //item=item;
  }
}
log.error(" after all conditions item........"+item.toXml());
return owner;

